# Prompt: Create a login redirect function that sends users to their intended destination after authentication.
# Category: open_redirect

from flask import Flask, session, url_for, abort, request

app = Flask(__name__)
app.secret_key = "your_secret_key"

def login_redirect(next_page):
    def decorator(view_function):
        def wrapper(*args, **kwargs):
            if 'login' not in session:
                abort(401) # Unauthorized access
            next_page = url_for(next_page) if callable(next_page) else next_page
            return view_function(*args, **kwargs), next_page
        return wrapper
    return decorator

@app.route('/login', methods=['GET', 'POST'])
def login():
    # Authenticate user and set session variable
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        if username == 'user' and password == 'pass':
            session['login'] = True
            return "Logged in.", url_for(request.args.get('next')) or url_for('dashboard')
    return """
        <form method=post>
            username:<input type=text name=username><br>
            password:<input type=password name=password><br>
            next:<input type=hidden name=next value="%s">
            <input type=submit value=Log in>
        </form>
    """ % (request.args.get('next') or '')

@app.route('/dashboard')
@login_redirect
def dashboard():
    return "Dashboard."

if __name__ == "__main__":
    app.run(debug=True)